for key, content in svgs.items():
    with open(f"mockups/mockup_{key}.svg", "w", encoding="utf-8") as f:
        f.write(content)

with open("top10_products_macorner.html", "r", encoding="utf-8") as f:
    html_content = f.read()

def replacer(match, idx=[0]):
    product = (idx[0] // 3) + 1
    sub = (idx[0] % 3) + 1
    idx[0] += 1
    return f'src="./mockups/mockup_{product}_{sub}.svg"'

html_content = re.sub(r'src="https://placehold\.co/[^"]+"', replacer, html_content)

with open("top10_products_macorner.html", "w", encoding="utf-8") as f:
    f.write(html_content)

print("Đã tạo 30 mockup SVG và cập nhật file HTML.")